// // This module counts down from 15 to 0 on each positive edge of the clock and resets to 16 when the reset signal is high.
module binary_up_counter_4bit(
    input clk,
    input reset,
    output reg [3:0] count
);

always @(posedge clk) begin
    if (reset)
        count <= 4'b0000;
    else
        count <= count + 1;
end

endmodule
